| MCP:jggXLF | #!/usr/bin/env bash
| MCP:jggXLF | set -euo pipefail
| MCP:jggXLF | TARGET=${1:-127.0.0.1}
| MCP:jggXLF | case "$TARGET" in
| MCP:jggXLF |   127.0.0.1|localhost) ;;
| MCP:jggXLF |   *) echo "Refusing to scan non-local target: $TARGET" >&2; exit 2 ;;
| MCP:jggXLF | esac
| MCP:jggXLF | nmap -sV --top-ports 100 -oX reports/local_scan.xml "$TARGET"
